import { Liveblocks } from "@liveblocks/node";
import { NextRequest } from "next/server";

export async function POST(request: NextRequest) {
  const liveblocks = new Liveblocks({
    secret: process.env.LIVEBLOCKS_SECRET_KEY as string,
  });

  const user = { id: "user_" + Math.random().toString(36).substring(2, 9), info: {} };

  const { status, body } = await liveblocks.identifyUser(
    {
      userId: user.id,
      groupIds: [],
    },
    { userInfo: user.info }
  );

  return new Response(body, { status });
}

"use client";

import { LiveblocksProvider, RoomProvider, useMyPresence, useOthers, useSelf } from "@liveblocks/react";
import { useState, useEffect } from "react";

export function Providers({ children }: { children: React.ReactNode }) {
  // If the prompt strictly says "the client uses NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY", maybe we should pass it.
  // But it also says "Authentication uses /api/liveblocks-auth with LIVEBLOCKS_SECRET_KEY on the server".
  // Let's use authEndpoint.
  return (
    <LiveblocksProvider authEndpoint="/api/liveblocks-auth">
      {children}
    </LiveblocksProvider>
  );
}

export function Room({ children }: { children: React.ReactNode }) {
  const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID || 'default'}`;
  return (
    <RoomProvider id={roomId} initialPresence={{ color: "#000000" }}>
      {children}
    </RoomProvider>
  );
}

"use client";

import { Providers, Room } from "./Providers";
import { useMyPresence, useOthers, useSelf } from "@liveblocks/react";
import { Suspense } from "react";

function ColorPicker() {
  const [myPresence, updateMyPresence] = useMyPresence();
  const others = useOthers();
  const self = useSelf();

  const handleColorChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateMyPresence({ color: e.target.value });
  };

  if (!self) {
    return null;
  }

  return (
    <main className="p-8">
      <h1 className="text-2xl mb-4">Liveblocks Collaborative Color Picker</h1>

      <div className="mb-8">
        <label htmlFor="color-input" className="block mb-2">Pick your color:</label>
        <input 
          id="color-input" 
          type="color" 
          value={myPresence.color !== undefined ? myPresence.color : "#000000"} 
          onChange={handleColorChange} 
        />
      </div>

      <h2 className="text-xl mb-4">Users</h2>
      <ul id="user-colors" className="flex gap-4 flex-wrap">
        <li
          data-connection-id={self.connectionId}
          data-color={myPresence.color || "#000000"}
          style={{ backgroundColor: myPresence.color as string || "#000000" }}
          className="w-16 h-16 rounded-full border border-gray-300 flex items-center justify-center text-xs"
        >
          Me
        </li>

        {others.map((other) => {
          const color = other.presence?.color as string || "#000000";
          return (
            <li
              key={other.connectionId}
              data-connection-id={other.connectionId}
              data-color={color}
              style={{ backgroundColor: color }}
              className="w-16 h-16 rounded-full border border-gray-300 flex items-center justify-center text-xs"
            >
              User {other.connectionId}
            </li>
          );
        })}
      </ul>
    </main>
  );
}

export default function Home() {
  return (
    <Providers>
      <Room>
        <Suspense fallback={<div>Loading...</div>}>
          <ColorPicker />
        </Suspense>
      </Room>
    </Providers>
  );
}

